<?php $page_title='Reset Password'; require_once __DIR__.'/../includes/header.php'; $tok=$_GET['token']??($_POST['token']??'');
if($_SERVER['REQUEST_METHOD']==='POST'){ verify_csrf(); $pass=$_POST['password']??''; if(strlen($pass)<8) flash('error','Password must be at least 8 characters.'); else {$stmt=db()->prepare('SELECT * FROM password_resets WHERE token=? AND used_at IS NULL AND expires_at > ? LIMIT 1');$stmt->execute([$tok,now()]);$r=$stmt->fetch(); if($r){db()->prepare('UPDATE users SET password_hash=?, updated_at=? WHERE id=?')->execute([password_hash($pass,PASSWORD_DEFAULT),now(),$r['user_id']]);db()->prepare('UPDATE password_resets SET used_at=? WHERE id=?')->execute([now(),$r['id']]);flash('success','Password updated. Sign in.');redirect('auth/login.php');} else flash('error','Invalid or expired token.');}}
?>
<section class="auth-page"><div class="card auth-card"><h1>Reset Password</h1><form class="form" method="post"><?= csrf_field() ?><input type="hidden" name="token" value="<?= e($tok) ?>"><input type="password" name="password" placeholder="New password" required minlength="8"><button class="btn full">Update Password</button></form></div></section>
